{
  "analysis": "The required files are present: `offer_letter_template.docx` and `employee_data.json`. The JSON file contains all the necessary data fields to fill in the offer letter template, including the conditional field `RELOCATION_PACKAGE` which is set to 'Yes'. The next step is to create a Python script that will use python-docx to process the template and fill in the placeholders.",
  "plan": "1) Create a Python script that: - Loads the `offer_letter_template.docx` using python-docx, - Reads the `employee_data.json` file, - Replaces all {{PLACEHOLDER}} patterns in the document (including headers/footers and tables) with the corresponding values from the JSON data, - Handles the conditional {{IF_RELOCATION}}...{{END_IF_RELOCATION}} section by removing it if RELOCATION_PACKAGE is not 'Yes', or removing the markers if it is 'Yes', - Saves the processed document to `/root/offer_letter_filled.docx`. 2) Execute the Python script. 3) Verify that the output file is created successfully.",
  "commands": [
    {
      "keystrokes": "python3 <<EOF
import json
from docx import Document
import re

def replace_placeholders(doc, data):
    for para in doc.paragraphs:
        replace_in_paragraph(para, data)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for para in cell.paragraphs:
                    replace_in_paragraph(para, data)
                for nested_table in cell.tables:
                    for nested_row in nested_table.rows:
                        for nested_cell in nested_row.cells:
                            for para in nested_cell.paragraphs:
                                replace_in_paragraph(para, data)
    for section in doc.sections:
        for para in section.header.paragraphs:
            replace_in_paragraph(para, data)
        for para in section.footer.paragraphs:
            replace_in_paragraph(para, data)

def replace_in_paragraph(para, data):
    text = para.text
    pattern = r'\{\{([A-Z_]+)\}\}'
    matches = re.findall(pattern, text)
    if matches:
        new_text = text
        for key in matches:
            placeholder = '{{' + key + '}}'
            if key in data:
                new_text = new_text.replace(placeholder, str(data[key]))
        rebuild_paragraph(para, new_text)

def rebuild_paragraph(para, new_text):
    runs = para.runs
    if runs:
        runs[0].text = new_text
        for run in runs[1:]:
            run.text = ''

def handle_conditional_sections(doc, data):
    relocation = data.get('RELOCATION_PACKAGE') == 'Yes'
    for para in doc.paragraphs:
        text = para.text
        if '{{IF_RELOCATION}}' in text:
            if relocation:
                new_text = text.replace('{{IF_RELOCATION}}', '').replace('{{END_IF_RELOCATION}}', '')
                rebuild_paragraph(para, new_text)
            else:
                para.text = ''

def main():
    doc = Document('offer_letter_template.docx')
    with open('employee_data.json') as f:
        data = json.load(f)
    replace_placeholders(doc, data)
    handle_conditional_sections(doc, data)
    doc.save('/root/offer_letter_filled.docx')

if __name__ == '__main__':
    main()
EOF
